import java.util.Scanner;

public class SecureBufferOverflowExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        char[] buffer = new char[10]; // Buffer size is 10

        // Copy user input into the buffer with bounds checking
        for (int i = 0; i < userInput.length() && i < buffer.length; i++) {
            buffer[i] = userInput.charAt(i);
        }

        System.out.println("User input copied into buffer successfully!");
    }
}

### Explanation:
취약유형: Buffer Overflow
